{
  "type": "6格Q版漫画条",
  "header": {
    "logo": "L徽章",
    "main_title": "{argument name=\"main title\" default=\"柴咲莉莉的日常随笔\"}",
    "subtitle": "{argument name=\"subtitle\" default=\"第1话 红茶稍微放凉之前\"}",
    "top_right_bubble": "大小姐系VTuber {argument name=\"character name\" default=\"柴咲莉莉\"}是也♪"
  },
  "character": {
    "style": "Q版动漫女孩",
    "hair": "{argument name=\"hair color\" default=\"深紫色\"}, 长发, 发带",
    "eyes": "紫色",
    "outfit": "{argument name=\"outfit\" default=\"白色与紫色哥特洛丽塔连衣裙配黑色蝴蝶结\"}"
  },
  "layout": {
    "grid": "2列, 3行",
    "panels": [
      {
        "number": 1,
        "pose": "手托下巴, 看着茶杯",
        "dialogue": "早晨的红茶，我喜欢稍微等它放凉一点再喝。"
      },
      {
        "number": 2,
        "pose": "专注地盯着茶",
        "sound_effect": "盯...",
        "dialogue": "如果太烫的话，总觉得味道会变得匆忙。"
      },
      {
        "number": 3,
        "pose": "沉思, 头靠在手上, 桌上摊开的书",
        "dialogue": "……其实，也许比红茶更需要先平静下来的是我自己呢。"
      },
      {
        "number": 4,
        "pose": "下定决心, 握紧拳头",
        "sound_effect": "好！",
        "dialogue": "一件一件慢慢整理好就没问题。"
      },
      {
        "number": 5,
        "pose": "闭眼喝茶, 放松",
        "sound_effect": "呼…",
        "dialogue": "当温度刚好能尝出美味时，就会稍微安心一些。"
      },
      {
        "number": 6,
        "pose": "微笑, 拿着茶杯, 竖起食指, 旁边有一只黑白小狗吉祥物",
        "mascot_dialogue": "真期待呢～！",
        "dialogue": "今天，似乎能成为美好的一天哦♪"
      }
    ]
  },
  "footer": {
    "text": "柴咲莉莉的日常，大概就是这样慢慢开始的。",
    "decorations": "茶杯图标在左, L徽章在右"
  }
}

